//演示| || 使用

public class LogicOperator02 { 

	//编写一个main方法
	public static void main(String[] args) {

		//||短路或  和 |逻辑或 案例演示
		//|| 规则: 两个条件中只要有一个成立，结果为true,否则为false
		//| 规则: 两个条件中只要有一个成立，结果为true,否则为false
		int age = 50;
		if(age > 20 || age < 30) {
			System.out.println("ok100");
